SELECT * FROM gl_balance
WHERE company_id = #{companyId}
AND account_id = #{accountId}
AND accounting_year = #{accountingYear}
AND accounting_period = #{accountingPeriod}
AND is_deleted = 0
LIMIT 1

SELECT * FROM gl_balance
WHERE company_id = #{companyId}
AND accounting_year = #{accountingYear}
AND accounting_period BETWEEN #{startPeriod} AND #{endPeriod}

    AND account_id IN

        #{id}


AND is_deleted = 0
ORDER BY account_code, accounting_period

SELECT b.* FROM gl_balance b

    b.company_id = #{companyId}
    AND b.accounting_year = #{accountingYear}
    AND b.accounting_period = #{endPeriod}

        AND b.account_code LIKE CONCAT('%', #{accountCodeLike}, '%')


        AND b.account_name LIKE CONCAT('%', #{accountNameLike}, '%')


        AND (b.ending_debit > 0 OR b.ending_credit > 0)

    AND b.is_deleted = 0

ORDER BY b.account_code
